INSERT INTO `tl_news` (`id`, `pid`, `tstamp`, `headline`, `alias`, `author`, `date`, `time`, `subheadline`, `teaser`, `addImage`, `singleSRC`, `alt`, `size`, `imagemargin`, `imageUrl`, `fullsize`, `caption`, `floating`, `addEnclosure`, `enclosure`, `source`, `jumpTo`, `articleId`, `url`, `target`, `cssClass`, `noComments`, `featured`, `published`, `start`, `stop`) VALUES
(1, 1, 1484046530, 'In hac habitasse platea dictumst', 'in-hac-habitasse-platea-dictumst', 1, 1466348100, 1466348100, '', '<p>Sed vel tortor purus. Duis felis tortor, lacinia eu quam quis, elementum suscipit eros. Quisque leo turpis, gravida pulvinar consectetur id, mollis sed ante. Fusce viverra, ipsum eget convallis convallis, nulla eros sollicitudin tellus, sit amet eleifend massa quam sed sem. Morbi hendrerit consequat ex sed convallis. Sed varius, quam vitae blandit feugiat, metus mauris dapibus risus, ut vestibulum nunc urna rhoncus est.</p>', '1', 0x99d11585d36311e684a829e919be70f5, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'left', '', NULL, 'default', 0, 0, '', '', '', '', '', '', '', ''),
(2, 1, 1484046531, 'Donec euismod arcu et sapien feugiat', 'donec-euismod-arcu-et-sapien-feugiat', 1, 1465743600, 1465743600, '', '<p>Vestibulum non dictum ante, eleifend bibendum metus. Curabitur consequat eget tellus id efficitur. Integer euismod laoreet urna. Maecenas a vulputate turpis, quis fringilla diam. Nam iaculis, mi in varius tempor, est nisi ullamcorper lacus, eu condimentum ipsum ligula sed purus. Morbi porta imperdiet tortor in varius. Proin in lobortis nunc. Donec ipsum diam, feugiat in nunc eget, malesuada ultricies sem.</p>', '1', 0x75d54e127a6611e6acef002590ae6f1e, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'left', '', NULL, 'default', 0, 0, '', '', '', '', '', '', '', ''),
(3, 1, 1484044463, 'Abmeldung &#40;Status 6&#41; unseres TSF', 'abmeldung-status-6-unseres-tsf', 1, 1469631660, 1469631660, 'gravierender Mängel bei der TÜV Prüfung', '<div>Wegen[nbsp]gravierender Mängel bei der[nbsp]TÜV[nbsp]Prüfung (zwei Seiten),[nbsp]ist es nicht mehr möglich[nbsp]sicher am Straßenverkehr teilzunehmen.</div>\n<div>Aufgrund des Alters, in Verbindung mit den geschätzten[nbsp]hohen Reparaturkosten,[nbsp]ist nicht mehr davon auszugehen, dass diese Mängel durch die Gemeinde Kallmünz beseitigt werden.</div>\n<div>Um die Einsatzfähigkeit aufrecht zu erhalten, wurde uns von der Feuerwehrschule Regensburg ein TSF zur Verfügung gestellt.</div>', '1', 0x33c94b97d71e11e684a829e919be70f5, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'left', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(4, 1, 1484046528, 'Nunc varius sit amet mi id blandit', 'nunc-varius-sit-amet-mi-id-blandit', 1, 1466348460, 1466348460, '', '<p>Vestibulum non dictum ante, eleifend bibendum metus. Curabitur consequat eget tellus id efficitur. Integer euismod laoreet urna. Maecenas a vulputate turpis, quis fringilla diam. Nam iaculis, mi in varius tempor, est nisi ullamcorper lacus, eu condimentum ipsum ligula sed purus. Morbi porta imperdiet tortor in varius. Proin in lobortis nunc. Donec ipsum diam, feugiat in nunc eget, malesuada ultricies sem.</p>', '1', 0x99d11565d36311e684a829e919be70f5, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:4:\"crop\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'left', '', NULL, 'default', 0, 0, '', '', '', '', '', '', '', ''),
(5, 1, 1484046529, 'Sit amet mi id blandit', 'sit-amet-mi-id-blandit', 1, 1466347860, 1466347860, '', '<p>Vestibulum non dictum ante, eleifend bibendum metus. Curabitur consequat eget tellus id efficitur. Integer euismod laoreet urna. Maecenas a vulputate turpis, quis fringilla diam. Nam iaculis, mi in varius tempor, est nisi ullamcorper lacus, eu condimentum ipsum ligula sed purus. Morbi porta imperdiet tortor in varius. Proin in lobortis nunc.</p>', '1', 0x99d115a5d36311e684a829e919be70f5, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'left', '', NULL, 'default', 0, 0, '', '', '', '', '', '', '', ''),
(6, 1, 1483783288, 'Mitgliederversammlung', 'mitgliederversammlung', 1, 1483701780, 1483701780, 'Jahreshauptversammlung der FF Traidendorf', '<p>Am 5. Januar 2017 hat der Feuerwehrverein seine ordentliche Mitgliederversammlung abgehalten. Unser 1. Vorstand Alfred Schmid berichtete den anwesenden Mitgliedern, über die Arbeit des Vereins. Der 1. Kommandant Holger Karl zog Bilanz. Als Gäste und Redner waren der erste Bürgermeister <span class=\"st\">Ulrich</span> <span class=\"st\">Brey und Kreisbrandmeister Josef Pretzl zu gast.</span></p>', '1', 0x67eb910cd40311e684a829e919be70f5, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'left', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(7, 1, 1483998915, 'Unsere Fahne', 'unsere-fahne', 1, 1483545600, 1483545600, 'wird restauriert', '<p>Nach fast einem Jahr ist es nun soweit. Unsere Fahne befindet sich seit dem 4. Januar 2017 bei einer Restauratorin.</p>\n<p>Viele Jahre im Gasthaus hinter Glas, hat der alten Fahne schwer zugesetzt. Die Reparatur der Fahne kostet ca. ein Drittel einer Neuanschaffung. Daher hat sich der Vorstand zur Wiederherstellung der Fahne entschlossen. Die Arbeiten können bis zu einem halben Jahr andauern.</p>', '1', 0xf6a6a672d6b211e684a829e919be70f5, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(8, 1, 1484651323, 'FF bekommt neus TSF', 'ff-bekommt-neus-tsf', 1, 1484650500, 1484650500, 'Einweihung 1. Juli 2017', '<p style=\"text-align: left;\" align=\"justify\">Am 1. Juli 2017 wird ab 16:00 Uhr, die Einweihung des neuen Tragkraftspritzenfahrzeuges und die Restaurierung der Vereinsfahne in Traidendorf gefeiert.</p>\n<p style=\"text-align: left;\" align=\"justify\">Es wurden die 16 Feuerwehrvereine der Verwaltungsgemeinschaft Kallmünz eingeladen und die Musikkapelle der Blaskapelle Dietldorf verpflichtet.</p>', '1', 0xd59359b7dca311e69b3bfbbcbd8047e4, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'internal', 83, 0, '', '', '', '', '', '1', '', ''),
(9, 1, 1515068666, 'Neues TSF', 'neues-tsf', 1, 1489230780, 1489230780, 'Erste Eindrücke vom Fahrgestell', '<p>Das Fahrgestell wurden nun endlich zur Fa. Moser nach Heitzenhofen geliefert.</p>\n<p>Unsere Kommandanten und Vorstände[nbsp]haben das neue TSF - Fahrgestell[nbsp]besichtigt.</p>\n<p>Hier sind die ersten Bilder, ohne Aufbauten und Ausrüstung. Vor dem Ausbau findet die Konservierung des Fahrzeugs am 11. März 2017 statt.</p>', '1', 0x5bbe732b064e11e790ca02a73e4087e3, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 83, 0, '', '', '', '1', '', '1', '', ''),
(10, 1, 1515067313, 'Aufbaubesprechung', 'aufbaubesprechung', 1, 1487612940, 1487612940, 'Aufbaubesprechung Furtner & Ammer', '<p style=\"-qt-block-indent: 0; text-indent: 0px; margin: 0px;\">Der erste Kommandant Holger Karl und der erste Vorsitzende waren zur Aufbaubesprechung bei der Firma Furtner [&] Ammer in Landau a.d.I..</p>\n<p style=\"-qt-block-indent: 0; text-indent: 0px; margin: 0px;\">Aufgrund der interkommunalen Zusammenarbeit mit der Stadt Teublitz waren auch Vertreter der FF Premberg[nbsp]anwesend. [nbsp][nbsp]</p>', '1', 0xd3dfa043074b11e790ca02a73e4087e3, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 83, 0, '', '', '', '1', '', '1', '', ''),
(11, 1, 1490533479, 'Kleinübung', 'kleinuebung', 1, 1490389320, 1490389320, 'Kuppeln', '<p>Unter der Leitung unseres Kommandanten Andreas Baumer, fand am 24. März 2017 eine Übung der FF Traidendorf statt. Trainiert wurde der Aufbau (Kuppeln) einer Wasserversorgung aus Gewässern mit der mobilen Pumpenanlage sowie das einrichten und anlegen von Seilen zum Bergen von Personen.</p>', '1', 0xaaf05bc810d411e790ca02a73e4087e3, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 83, 0, '', '', '', '', '', '1', '', ''),
(12, 1, 1515068978, 'TSF Übergabe', 'tsf-uebergabe', 1, 1498138920, 1498138920, 'Willkommen in Traidendorf', '<p>Unser neues TSF kommt nach Traidendorf.</p>\n<p>Vertreter der FF übernehmen das neue Einsatzfahrzeug und Ausrüstung. Bei der Übergabe werden die anwesenden Vertreter der FF im Umgang mit Fahrzeug und Ausrüstung unterwiesen. Bei der Ankunft im Dorf, besteht die Möglichkeit, unser neues TSF zu besichtigen.</p>', '1', 0x1ecedd29575b11e7972eef89e1cd5d6a, 'Abfahrt nach Traidendorf', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(14, 1, 1515069426, 'Die Einweihung', 'dieeinweihung', 2, 1498924800, 1498924800, '', '<p>Am 01.07.2017 konnten wir unser neues TSF[nbsp]gebührend einweihen[nbsp]und seine Indienststellung feiern. Weiter wurde [nbsp]der gesponserte MicroCafs[nbsp]durch Hr. Ritz übergeben.[nbsp][nbsp]</p>\n<p>Hier ein paar Bilder des Tages.[nbsp][nbsp][nbsp]</p>', '1', 0x90fc4585e72411e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(17, 2, 1514411957, 'Rauchwarnmelderpflicht ab 01.01.2018', 'rauchwarnmelderpflicht', 2, 1514412000, 1514412000, '', '<p>Ab 01.01.2018 gilt die Rauchwarnmelderpflicht in Bayern.</p>\n<p>Hier im Anhang finden Sie alle[nbsp]wichtigen Fragen und Antworten.[nbsp]</p>', '1', 0x37521126eb3e11e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', 0x613a313a7b693a303b733a31363a221c42505feb4011e78ee9d7222140dd97223b7d, 'default', 86, 0, '', '', '', '1', '', '1', '', ''),
(18, 2, 1515066201, 'Rettungspunkt Forst', 'rettungspunkt-forst-18', 2, 1514410920, 1514410920, '', '<p>Im Anhang finden Sie den Flyer \"Richtig Retten\" sowie die Rettungspunkte rund um Traidendorf.</p>', '1', 0xf9993397eb4e11e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', 0x613a313a7b693a303b733a31363a22c81b1898eb4d11e78ee9d7222140dd97223b7d, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(19, 1, 1514414047, 'Vatertagswanderung', 'vatertagswanderung', 1, 1495713600, 1495713600, 'Christi Himmelfahrt', '<p>Der volkstümliche Vatertag wird in Deutschland an <a title=\"Christi Himmelfahrt\" href=\"https://de.wikipedia.org/wiki/Christi_Himmelfahrt\">Christi Himmelfahrt</a> begangen, dem 40.[nbsp]Tag des <a title=\"Ostern\" href=\"https://de.wikipedia.org/wiki/Ostern\">Osterfestkreises</a>. Er wird vor allem in <a title=\"Ostdeutschland\" href=\"https://de.wikipedia.org/wiki/Ostdeutschland\">Ostdeutschland</a><sup id=\"cite_ref-1\" class=\"reference\"><a href=\"https://de.wikipedia.org/wiki/Vatertag#cite_note-1\">[1]</a></sup> auch als <em>Herrentag</em> bezeichnet, wobei im Brauchtum oft die „Herrentagspartie“ im Vordergrund steht. In Sachsen und <a title=\"Thüringen\" href=\"https://de.wikipedia.org/wiki/Th%C3%BCringen\">Thüringen</a> wird auch die Bezeichnung „Männertag“ verwendet.<sup id=\"cite_ref-TA_2-0\" class=\"reference\"></sup></p>', '1', 0x1d755ca6eb5211e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(20, 1, 1515151290, 'Aufbau TSF-Weihe', 'aufbau-tsf-weihe', 1, 1498777200, 1498777200, 'alle packen an', '<p>Das ganze Dorf packt mit an. Impressionen zum Aufbau auf der Festwiese.</p>', '1', 0x72b7f73bf0d711e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '1', '', '1', '', ''),
(21, 1, 1515068922, 'Besichtigung Furtner [&] Ammer', 'besichtigung-furtner-ammer', 1, 1496358000, 1496358000, 'Traidendorfer Kameraden zur Werksbesichtigung', '<p>Aufgrund der Neubeschaffung unseres TSF[nbsp]öffnete[nbsp]die Fa. Furtner und Ammer in Landau a.d.I. ihre Tore für eine[nbsp]Firmenbesichtigung. Dem Angebot zu diesem Ausflug[nbsp]folgten 15 Kameraden. Nach einer 1 1/2 Std. Führung durch Hr. Furtner[nbsp]Sen. verbrachten die Kameraden noch einen gemütlichen Nachmittag im Biergarten in Adlersberg.[nbsp][nbsp]</p>', '1', 0xb857b84af0db11e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '1', '', '1', '', ''),
(22, 1, 1515022136, 'Johannisfeuer', 'johannisfeuer', 1, 1498172400, 1498172400, 'es brennt im Dorf', '<p>Trotz der aufwendigen Vorbereitungen zur Einweihung des neuen Tragkraftspritzenfahzeugs der FF findet auch in diesem Jahr unser Johannesfeuer statt.</p>', '1', 0xd06cfccdf0dc11e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '1', '', '1', '', ''),
(23, 1, 1515068790, 'Floriansübung', 'floriansuebung', 1, 1493852700, 1493852700, 'in Holzheim', '<p>Der Förderverein des Feuerwehrwesens hat zur Floriansübung in Holzheim am Forst geladen.</p>\n<p>Die Kallmünzer FF simulierte die Bergung eines verletzten aus einem verunfalltem Auto. Die[nbsp]Rolle des Verletzten übernahm Hr.[nbsp]Pfarrer Gierl.[nbsp]</p>\n<p>Ebenso wurde ein Kreuz aus den Steckleitern geformt.</p>', '1', 0xe428577bf0e111e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '1', '', '1', '', ''),
(24, 1, 1515069694, 'Ehrenzeichen verliehen', 'ehrenzeichen-verliehen', 1, 1505863200, 1505863200, 'Landrätin und KBR', '<p>Auch in diesem Jahr wurden wieder Kameraden aus unseren Reihen mit dem Feuerwehrehrenzeichen geehrt. Zwei Kameraden mit 25 Jahren und zwei Kameraden mit 40 Jahren im[nbsp]aktiven Dienst wurden durch[nbsp]die Landrätin des Landkreises Regensburg, Tanja Schweiger und dem Kreisbrandrat Wolfgang Scheuerer[nbsp]geehrt. Die Verleihung[nbsp]fand dieses mal im Landgasthof \"Zum Birnthaler\" in Krachenhausen statt.</p>', '1', 0x21eb775af0e411e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '1', '', '1', '', ''),
(25, 1, 1515026636, 'Hofweihnacht', 'hofweihnacht', 1, 1512864000, 1512864000, 'im Fantehof', '<p>Zum ersten mal veranstalteten die traidendorfer Vereine eine Hofweihnacht auf dem Hof der Familie Fleischmann. Die Einnahmen aus dem Verkauf, spenden die Vereine und die Familie Fleischmann an die <a href=\"http://www.uniklinikum-regensburg.de/ueber-uns/Pflegedienst/Stationen_und_Ambulanzen/KUNO___Kinderklinik/\" target=\"_blank\">Kinderklinik Kuno in Regensburg</a>.</p>', '1', 0x0e0c4355f0e711e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '1', '', '1', '', ''),
(26, 1, 1515069486, 'Übung am neuen TSF', 'uebung-am-neuen-tsf', 1, 1500076320, 1500076320, 'erste Übung', '<p>Der Kommandant der FF Traidendorf lud zur ersten Übung mit dem neuen TSF.</p>\n<p>Schwerpunkt hier war das \"kennenlernen\"[nbsp]der neuen Gerätschaften.</p>\n<p>In den nächsten Übungen soll dann die Handlungssicherheit gefestigt werden.</p>', '1', 0x7aeae6cef0e811e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '1', '', '1', '', ''),
(27, 1, 1515068484, 'Konservierung', 'konservierung', 1, 1489194480, 1489194480, 'selbst gemacht', '<p>Unsere Fachmänner legen Hand an. Das[nbsp]Fahrgestell ist geliefert.</p>\n<p>Doch bevor[nbsp]das Fahregstell an die[nbsp]Firma Furtner und Ammer nach Landau a.d.I. überführt wird um den Aufbau und die Ausrüstung zu realisieren, leistet die FF Traidendorf auch ihren Teil zur Neubeschaffung. Um den Witterungseinflüssen vor allem im Winter vorzubeugen, versiegeln[nbsp]die Kameraden unserer Wehr den Unterboden.</p>', '1', 0xc010f073f0ea11e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '1', '', '1', '', ''),
(28, 1, 1515070373, 'MicroCAFS MC6SP10', 'cafs-mc6sp10', 1, 1498818420, 1498818420, 'REGAS spendet Druckluftschaumlöscher', '<p>Die <a href=\"http://www.regas-regensburg.de/\" target=\"_blank\">REGAS</a> spendet der FF Traidendorf zur TSF Weihe einen[nbsp]<a href=\"https://de.wikipedia.org/wiki/Druckluftschaum\" target=\"_blank\">CAFS (Compressed Air Foam System)</a> Druckluftschaumlöscher.</p>\n<p>Auch hier nochmal unseren herzlichen Dank für diese großzügige Spende!!!</p>', '1', 0xbd98cac2f14211e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(29, 1, 1515069745, 'Rauhnacht', 'rauhnacht', 1, 1514464200, 1514464200, 'in Traidendorf', '<p>Die Rauhnächte (auch Raunächte oder Rauchnächte), zwölf Nächte (auch Zwölfte), Glöckelnächte, Innernächte oder Unternächte sind einige Nächte um den Jahreswechsel, denen im europäischen <a title=\"Brauch\" href=\"https://de.wikipedia.org/wiki/Brauch\">Brauchtum</a> oft besondere Bedeutung zugemessen wird.</p>', '1', 0x74b75dabf14a11e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(31, 1, 1515086375, 'Pferdesegnung', 'pferdesegnung', 1, 1509901920, 1509901920, 'Schutzpatron der heiligen Kirche', '<p>Herr Pfarrer Giehrl, hatte anlässlich des Todestages der Hl. Leonhardes und Schutzpatron der heiligen Kirche, am Stockhäusl zur Andacht und anschließenden Pferdesegnung geladen. Es waren ca. 30 Pferde samt Reiter und zahlreiche Zuschauer gekommen. Die FF Traidendorf hat bei dieser Veranstaltung die Bewirtung der Gäste übernommen.</p>', '1', 0x58f93076f17211e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(32, 1, 1515095789, 'Halloween', 'halloween', 1, 1509479520, 1509479520, 'Monster am Feuer', '<p>An diesem Abend haben sich nicht nur kleine Monster am Feuer der FF Traidendorf gewärmt.</p>', '1', 0x41922976f18811e78ee9d7222140dd97, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(33, 2, 1533997169, 'Sicherheitshinweis zu Motorsägen der Fa. Dolmar', 'SicherheitshinweiszuMotorsägenderFaDolmar', 2, 1533996660, 1533996660, '', '<p>Die Firma Dolmar hat einen Sicherheitshinweis für einige ihrer Benzin-Kettensägen veröffentlicht. Es wurde festgestellt, dass bei den betroffenen Geräten die <strong>automatische Kettenbremse</strong> zu spät aktiviert werden könnte. Im Falle eines „Kick-Backs“ könnte dadurch die laufende Sägekette den Benutzer berühren. <strong>Die betroffenen Geräte dürfen nicht mehr verwendet oder weitergegeben werden</strong>.[nbsp]Weitere Informationen von der Fa. Dolmar hierzu sind unter diesem <a href=\"http://www.dolmar.de/service/sicherheitshinweis/sicherheitshinweis_fuer_benzin_kettensaegen.html\">Link </a>zu finden.</p>', '1', 0x5d3107029d7111e89e6500163ed9c081, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(34, 1, 1534680307, 'Übung mit Wasserentnahme', 'uebung-mit-wasserentnahme', 1, 1534679580, 1534679580, 'Wasserentnahme offenes Gewässer', '<p>Am 19. August übten die Kameraden der FF-Traidendorf die Wasserentnahme aus offenem Gewässer sowie den Aufbau bis zum Angriff. In einem weiteren Teil der Übung wurden die Kameraden im Umgang mit dem neuen CAFS-Feuerlöscher unterwiesen.</p>', '1', 0x0c509ef2a3a011e8bb9f00163ed9c081, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(35, 1, 1534699224, 'Fahrsicherheitstraining', 'fahrsicherheitstraining', 1, 1532174400, 1532174400, 'beim ADAC Regensburg', '<p>Am 21. Juli absolvierten zwei Maschinisten der FF-Traidendorf ein Fahrsicherheitstraining auf dem Übungsgelände des ADAC. An diesem Tag lernten die Kameraden den Grenzbereich von Mensch und Maschine kennen. Der Trainer des ADAC vermittelte zunächst, notwendige theoretische Grundlagen. Im praktischen Teil setzten die Teilnehmer das vermitelte Wissen um.</p>', '1', 0x6549a61ca3ad11e8bb9f00163ed9c081, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(36, 1, 1536776627, 'Jugendleistungsspange', 'jugendleistungsspange', 3, 1531548000, 1531548000, 'höchstes Abzeichen der Deutschen Jugendfeuerwehr', '<p>170 Jugendliche der Jugendfeuerwehr Landkreis Regensburg legen höchstes Abzeichen der Deutschen Jugendfeuerwehr ab.</p>', '1', 0x4be31b40b6b711e884c100163ed9c081, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(38, 2, 1537093372, 'Produktwarnung Fettbrandlöscher Mono F60', 'produktwarnungfettbrandloescher', 2, 1537092660, 1537092660, '', '<p>Die Berufsgenossenschaft Nahrungsmittel und Gastgewerbe (BGN) warnt dringend vor der Benutzung von Fettbrandlöschern des Typs Mono F60. Nach Mitteilung der BGN besteht der begründete Verdacht, dass ein Mono-F60-Löscher nicht das Originallöschmittel enthält. In diesem Fall ist er zur Fettbrandbekämpfung völlig ungeeignet und würde beim Einsatz zu lebensbedrohlichen Brandverletzungen führen.“</p>\n<p>[nbsp]</p>\n<p>Hier die Pressemitteilung der BGN.</p>', '1', 0x065da767b99711e884c100163ed9c081, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '1', 0x613a323a7b693a303b733a31363a22d32a20b8b99711e884c100163ed9c081223b693a313b733a31363a225956d291b99a11e884c100163ed9c081223b7d, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(39, 1, 1577706930, 'Kinderfest', 'kinderfest', 1, 1536489480, 1536489480, 'Feuerwehrförderverein VG Kallmünz', '<p>Am 09.09.2018 fand das Kinderfest der Feuerwehrförderverein VG Kallmünz in Traidendorf statt.</p>', '1', 0x52a7e37e2afa11ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(40, 1, 1577707902, 'Übung', 'uebung', 1, 1537095360, 1537095360, 'am Traidendorfer Schloß', '<p>Die Kameraden machen sich bei bestem Wetter mit Ihrem Gerät vertraut und belohnen sich anschließend beim Frühschoppen.</p>', '1', 0x74c8cfcd2afd11ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(41, 1, 1577709869, 'Burschenverein Kallmünz', 'burschenverein-kallmuenz', 1, 1559216400, 1559216400, 'Traidendorf sichert Umzug', '<p>Die Kameraden der Traidendorfer Feuerwehr sichern den Umzug des Burschenvereins Kallmünz.</p>', '1', 0x0afbc7d52b0211ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(42, 1, 1577801100, '3. Hofweihnacht', 'id-3-hofweihnacht', 1, 1575801660, 1575801660, 'im Fantehof', '<p>Auch in diesem Jahr veranstalteten der Verein und die Familie Fleischmann die 3. Traidendorfer Hofweihnacht im Fantehof.</p>', '1', 0x6e01e60b2bd611ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(43, 1, 1577797969, 'Mitgliederversamlung', 'mitgliederversamlung', 1, 1546686900, 1546686900, 'mit Ehrungen', '<p>Auf der Jahreshauptversammlung der FF Traidendorf ehrte und verabschiedete der Verein die Mitglieder Alfons Kaiser und Karl Gutenberger.</p>', '1', 0x913065912bc111ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(44, 1, 1577793705, 'Großübung', 'uebung-44', 1, 1564569600, 1564569600, 'mit Wasserrettung', '<p>Am 31. Juli 2019 führeten die Feuerwehren der Marktgemeinde Kallmünz eine Übung am Gewässer in Traidendorf ab. Die Feuerwehren simulierten einen Verkehrsunfall, bei dem ein PKW in fließendes fährt.</p>', '1', 0x326f78832bc511ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(45, 1, 1577799400, 'Kappenabend', 'kappenabend', 1, 1550928720, 1550928720, 'im Stockhäusl', '<p>Am 31. Februar 2019 feierten die Kameraden der FF ihren Kappenabend im Vereinshaus der Stockschützen.</p>', '1', 0x44f0ffbb2bd211ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(46, 1, 1577800346, 'Vatertagswanderung', 'vatertagswanderung-46', 1, 1559219940, 1559219940, 'der FF Traidendorf', '<p>Auch die Herren der FF Traidendorf waren an diesem Tag unterwegs um die örtlichen Wirtshäuser zu begehen.</p>', '1', 0xbb33609b2bd411ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(47, 1, 1577801868, 'Frühlingsfest', 'fruehlingsfest', 1, 1558790040, 1558790040, 'in Traidendorf', '<p>Die Traidendorfer feiern den Frühling, wie man das halt so macht bei uns.</p>', '1', 0x49562d5b2bd811ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(48, 1, 1577802822, 'UVV Unterweisung', 'uvv-unterweisung', 1, 1550240640, 1550240640, 'intensiv', '<p>Der 1. Kommandant Holger Karl, führte die Jährliche UVV Unterweisung durch. Im Anschluss gab es. nicht nur zu diesem Thema, regen Austausch unter den Teilnehmern.</p>', '1', 0x326f78832bc511ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '', '', ''),
(49, 1, 1577969428, 'Wir bauen', 'wir-bauen', 1, 1564753620, 1564753620, 'ein Pumpenhaus', '<p>Die Gemeinde braucht ein Pumpenhaus und die FF eine Toilettenanlage. Damit die Kosten im Rahmen bleiben, bauen die Kameraden der FF Traidendorf den Rohbau.</p>', '1', 0x766e707e2bdc11ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(50, 2, 1578243636, 'Bayerische Ehrenamtskarte', 'BayerischeEhrenamtskarte', 2, 1578231300, 1578231300, 'Bayerische Ehrenamtskarte für 25 Jahre &#40;Blau&#41; und 40 Jahre &#40;Gold&#41; aktiven Dienst!', '<p>Danke an alle Ehrenfrauen und Ehrenmänner unserer Stadt!</p>\n<p><strong><a href=\"https://www.regensburg.de/leben/ehrenamt/bayerische-ehrenamtskarte\" target=\"_blank\">Die Bayerische Ehrenamtskarte gilt bei allen Partnern in der Stadt Regensburg und bayernweit!</a></strong>!!!</p>', '1', 0xfd1929652fc011ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(51, 1, 1578391853, 'Alles Gute Hans', 'alles-gute-hans', 1, 1573294140, 1573294140, 'zum 70. Geburtstag', '<p>Der Vorstand der FF beglückwünscht, im Namen der FF Traidendorf, Hans Gessendorfer zum 70. Geburtstag.</p>', '1', 0xb9a33a49313511ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(52, 1, 1578392040, 'Einsatz im Dorf', 'einsatz-im-dorf', 1, 1569143520, 1569143520, 'Folgen eines Herrenabends', '<p>Ein Herrenabend hatte einen Komposthaufen in Brand gesetzt. Die Männer der FF konnten schlimmeres verhindern und einen Maulwurf retten.</p>', '1', 0xb9a0b794313511ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(53, 1, 1578392270, 'Anbau SSC', 'anbau-ssc', 1, 1559034960, 1559034960, 'wir bauen mit dem SSC', '<p>Alle helfen wieder zusammen beim Anbau des Gerätehauses des SSC.</p>', '1', 0xb9a33add313511ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(55, 1, 1578392582, 'Wir üben', 'wir-ueben', 1, 1554628860, 1554628860, 'für das Leistungsabzeichen', '<p>Unter Anleitung der erfahrenen Kameraden üben wir für das Leistungsabzeichen.</p>', '1', 0xb9a33aa0313511ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(56, 1, 1578392787, 'Erkundungsfahrt', 'erkundungsfahrt', 1, 1558171440, 1558171440, 'zur Vatertageswanderung', '<p>Die mutigen Männer der FF erkundeten die Strecke zur Vatertageswanderung auf Ihren Feuerrössern.</p>', '1', 0xb9977550313511ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(57, 1, 1578392994, 'Die Jugendfeuerwehr übte den Ernstfall', 'die-jugendfeuerwehr-uebte-den-ernstfall', 1, 1557394080, 1557394080, '24h im Einsatz', '<p>Feuerwehrfrauen und -männer müssen hart trainieren. Jugendliche aus dem Landkreis Regensburg waren 24 Stunden im Einsatz.</p>', '1', 0xb9a0b75a313511ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(58, 1, 1578393160, 'Ehrungen', 'ehrungen', 1, 1556184660, 1556184660, '40 und 25 Jahre', '<p>Die ehrte ihre Mitglieder Siegfried Ferch für 40 Jahre und Sebastian Finke für 25 Jahre aktiven Dienst.</p>', '1', 0xb9977586313511ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(59, 1, 1578394738, 'Mitgliederversamlung', 'mitgliederversamlung-59', 1, 1578221040, 1578221040, 'mit Gästen', '<p>Auf der MV legten die Vorstände und Kommandanten der FF Traidendorf Rechenschaft über das Jahr 2019 ab. Die Mitgliederversammlung entlastete den Vorstand einstimmig. Unsere Gäste...</p>', '1', 0xb0015c06313a11ea904edb336c865829, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(61, 2, 1583832239, 'Corona Hygienetipps für Mitarbeiter', 'coronahygiene', 2, 1583831580, 1583831580, 'Corona Hygienetipps für Mitarbeiter', '<p>Im Anhang finden Sie die zehn wichtigsten Hygienetipps um einer Infektion vorzubeugen.</p>\n<p>Weiter finden Sie unter folgendem Link[nbsp] <a href=\"https://www.bundesgesundheitsministerium.de/coronavirus.html\">(https://www.bundesgesundheitsministerium.de/coronavirus.html</a>) alle wichtigen Informationen direkt vom Bundesgesundheitsministerium.</p>\n<p>[nbsp]</p>\n<p>[nbsp]</p>', '1', 0xb26daafd62b011ea914fde40a3714c29, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '1', 0x613a313a7b693a303b733a31363a22b26daaf362b011ea914fde40a3714c29223b7d, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(60, 1, 1579343870, 'Weihnachtsbaum', 'weihnachtsbaum', 1, 1578763020, 1578763020, 'verbrennen', '<p>Die Traidendorfer verbrennen heuer Ihre Weihnachtsbäume auf der Festwiese gemeinsam und wärmen sich mit Getränken am Feuer.</p>', '1', 0xfbab1c3d39dc11ea904edb336c865829, '', 'a:3:{i:0;s:3:\"347\";i:1;s:3:\"260\";i:2;s:12:\"proportional\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(63, 1, 1598452770, 'Hygienekonzept', 'hygienekonzept', 1, 1598451840, 1598451840, 'Stockhäusl sonntags wieder geöffnet', '<p>Für uns als Vorstand hat die Unterstützung der Wiederaufnahme des Übungsbetriebs oberste Priorität. Des Weiteren liegt uns sehr viel daran, wieder ein aktives Vereinsleben zu etablieren. Ein wichtiger Baustein ist hierbei unser Stockhäusl...</p>', '1', 0xb26daafd62b011ea914fde40a3714c29, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '1', 0x613a313a7b693a303b733a31363a22cbefa0c9e7a811eaadcc30a6ad7337bc223b7d, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(65, 1, 1624190851, 'Jugendfeuerwehr startet durch', 'die-jugendfeuerwehr-startet-durch', 1, 1624185900, 1624185900, 'neu dabei', '<p>Unsere Jugendfeuerwehr wächst. Simon Schmid, Julian Piller und Mathieu Köhler sind der FF Traidendorf beigetreten.</p>', '1', 0xb7dd6a79d1b511eb90c0dd3984ed17a9, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(66, 1, 1624189543, 'Bronze und Silber', 'bronze-und-silber', 1, 1624186920, 1624186920, 'Leistungsabzeichen', '<p>Die Ausbildung der Jugend geht weiter. Das Ergebnis waren 3 mal Bronze und 1 mal Silber. Herzlichen Glückwunsch und danke für Euren Einsatz.</p>', '1', 0xbb36e713d1b811eb90c0dd3984ed17a9, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(67, 1, 1626269217, 'Übung FF Jugend', 'uebung-ff-jugend', 1, 1625922000, 1625922000, 'Löschaufbau', '<p>Erste Übung der Feuerwehrjugend in Traidendorf 2021</p>', '1', 0xd0c08aece4a411eb90c0dd3984ed17a9, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(68, 1, 1627557210, 'Mitgliederversammlung 2021', 'mitgliederversammlung-2021', 1, 1627236000, 1627236000, 'mit Neuwahlen', '<p>Der Verein der FF Traidendorf hat auf seiner MV Kommandanten, Vorstände und Kassenprüfer gewählt. Zu Gast waren der Bürgermeister der Marktgemeinde Kallmünz Ulrich Brey und Kreisbrandmeister[nbsp]Josef Pretzel.</p>', '1', 0x2dcca0f7edf311eb9046db336b7e379b, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(69, 1, 1627293906, 'Übung 2021', 'uebung-69', 1, 1627056000, 1627056000, 'Aktive wieder aktiv', '<p>Unter der Leitung von Gruppenführer Sigi Ferch und Maschinist Sebastian Köhler üben die Aktiven der FF Traidendorf.[nbsp]</p>', '1', 0x2c78dca1edf211eb9046db336b7e379b, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(70, 1, 1635247677, 'Leistungsprüfung-Die Gruppe im Löscheinsatz', 'leistungspruefung-die-gruppe-im-loescheinsatz', 1, 1635057000, 1635057000, 'gut vorbereitet', '<p>Die Leistungsprüfung-Die Gruppe im Löscheinsatz ist ein Leistungsabzeichen des Freistaates Bayern für alle Angehörigen von Feuerwehren.</p>\n<p>Letzte Übung vor der Leistungsprüfung.</p>', '1', 0x4dd8ad8e364e11ec90aedc3881ddd285, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(71, 1, 1636042328, 'Leistungsabzeichen', 'leistungsabzeichen-erhalten', 1, 1635602400, 1635602400, 'bestanden', '<p>Die Leistungsprüfung \"Die Gruppe im Löscheinsatz\" wurde erfolgreich absolviert.</p>\n<p><strong>Prüfer:</strong>[nbsp]KBI Dietz | KBM Ühlin | KBM Pretzl</p>\n<p><strong>Gäste:</strong>[nbsp]Michael Baumer[nbsp]| Ulrich Brey</p>', '1', 0xe0b3fb0d3d6411ec90aedc3881ddd285, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(72, 1, 1656414307, 'Floriansübung', 'FLORIANSÜBUNG22', 2, 1651680000, 1651680000, 'Floriansübung', '<p>Endlich heuer wieder die, mittlerweile schon traditionelle, Floriansübung. DieTraidendorfer Wehr hat es sich nicht nehmen lassen an dieser Übung, die immer am Namenstag unseres Schutzpatronen stattfindet, teilzunehmen.</p>', '1', 0x72527f03d47911ec9064dc34719ab0a5, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(73, 1, 1658402760, 'Johannifeuer', 'johannifeuer', 1, 1656172800, 1656172800, 'gefeiert', '<p>Endlich wieder ein Johannifeuer in Traidendorf. Gut gesichert durch die Jugendfeuerwehr.</p>', '1', 0x7ba92f3608df11ed8af6ccef4aa55cdb, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(74, 1, 1658404040, 'Christi Himmelfahrt', 'christi-himmelfahrt', 1, 1653559200, 1653559200, 'Vatertag', '<p>Die Herren waren unterwegs. 23 Km Wandern auf ganz hohem Niveau.</p>', '1', 0xf4d5521e08e311ed8af6ccef4aa55cdb, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(75, 1, 1658402692, 'Elfmeterturnier', 'elfmeterturnier', 1, 1656770400, 1656770400, 'Bayern Fanclub', '<p>Die Mannschaft der FF Traidendorf hat den 3. Platz von 28 belegt.</p>', '1', 0xa7db682308e711ed8af6ccef4aa55cdb, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
(76, 1, 1658403922, 'Preiswatten', 'preiswatten', 1, 1657987200, 1657987200, 'im Stockhäusl', '<p>Preiswatten mit Gästen aus Niederbayern und Kallmünz.</p>', '1', 0x9dd4383808e911ed8af6ccef4aa55cdb, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
