(78, 1, 1672774485, 'Einsatz', 'einsatz', 1, 1662742800, 1662742800, 'Dachstuhlbrand', '<p>Traidendorf ist zum Dachstuhlbrand in Eich gerufen worden.</p>\n<div id=\"gtx-trans\" style=\"position: absolute; left: -24px; top: -16px;\">[nbsp]</div>', '1', 0xa1aa56638b9d11eda0f655df624d5ce5, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
