(80, 1, 1672781914, 'Jugend packt an', 'jugend-packt-an', 1, 1662548400, 1662548400, 'Nachbarschaftshilfe', '<p>Helfen, wenn Hilfe benötigt wird.</p>', '1', 0xf632f9378ba011eda0f655df624d5ce5, '', 'a:3:{i:0;s:0:\"\";i:1;s:0:\"\";i:2;s:0:\"\";}', 'a:5:{s:6:\"bottom\";s:0:\"\";s:4:\"left\";s:0:\"\";s:5:\"right\";s:0:\"\";s:3:\"top\";s:0:\"\";s:4:\"unit\";s:0:\"\";}', '', '', '', 'above', '', NULL, 'default', 0, 0, '', '', '', '', '', '1', '', ''),
